import type { EnvValue } from '@prisma/generator'

/**
 * Resolves a generator output `EnvValue` to a concrete directory path,
 * expanding environment variable references when present.
 */
export function resolveOutputDir(output: EnvValue | null): string {
  if (!output) {
    throw new Error('Generator output directory is not configured')
  }
  if (output.fromEnvVar) {
    const value = process.env[output.fromEnvVar]
    if (!value) {
      throw new Error(`Environment variable "${output.fromEnvVar}" is not set`)
    }
    return value
  }
  if (!output.value) {
    throw new Error('Generator output directory value is empty')
  }
  return output.value
}

