import type { DMMF } from '@prisma/dmmf'

/** Generates a TypeScript `const enum` for a Prisma datamodel enum. */
export function generateEnumType(dmmfEnum: DMMF.DatamodelEnum): string {
  const values = dmmfEnum.values.map((v) => `  ${v.name} = '${v.name}',`).join('\n')
  return `export const enum ${dmmfEnum.name} {\n${values}\n}`
}

