import type { DMMF } from '@prisma/dmmf'

import { fieldToTsType, scalarTypeToTs } from './field-type-mapper'

function indentLines(lines: string[]): string {
  return lines.map((line) => `  ${line}`).join('\n')
}

/** Generates the TypeScript interface for a model's full record shape. */
export function generateModelInterface(model: DMMF.Model): string {
  const fields = model.fields.map((f) => `${f.name}: ${fieldToTsType(f)}`)
  return `export interface ${model.name} {\n${indentLines(fields)}\n}`
}

/**
 * Generates a `WhereInput` type that makes all scalar and enum fields optional,
 * suitable for use as a filter argument.  Relation fields are excluded since
 * REST filter payloads are flat.
 */
export function generateWhereInputType(model: DMMF.Model): string {
  const fields = model.fields
    .filter((f) => f.kind !== 'object')
    .map((f) => {
      const base = f.kind === 'scalar' ? scalarTypeToTs(f.type) : f.type
      return `${f.name}?: ${base} | null`
    })
  return `export interface ${model.name}WhereInput {\n${indentLines(fields)}\n}`
}

/**
 * Generates a `WhereUniqueInput` type scoped to the model's `@id` and
 * `@unique` fields, matching Prisma's own uniqueness semantics.
 */
export function generateWhereUniqueInputType(model: DMMF.Model): string {
  const fields = model.fields
    .filter((f) => (f.isId || f.isUnique) && f.kind !== 'object')
    .map((f) => {
      const type = f.kind === 'scalar' ? scalarTypeToTs(f.type) : f.type
      return `${f.name}?: ${type}`
    })
  return `export interface ${model.name}WhereUniqueInput {\n${indentLines(fields)}\n}`
}

/**
 * Generates a `CreateInput` type for new record creation.
 * Auto-generated (`@id`, `@default`, `@updatedAt`) and read-only fields are
 * made optional; non-nullable fields without defaults are required.
 * Relation fields are excluded — relations are managed separately via their
 * own endpoints.
 */
export function generateCreateInputType(model: DMMF.Model): string {
  const fields = model.fields
    .filter((f) => !f.isReadOnly && !f.isId && f.kind !== 'object')
    .map((f) => {
      const type = f.kind === 'scalar' ? scalarTypeToTs(f.type) : f.type
      const optional = !f.isRequired || f.hasDefaultValue || f.isUpdatedAt
      const nullable = !f.isRequired ? ' | null' : ''
      return `${f.name}${optional ? '?' : ''}: ${type}${nullable}`
    })
  return `export interface ${model.name}CreateInput {\n${indentLines(fields)}\n}`
}

