import fs from 'node:fs/promises'
import path from 'node:path'

import type { DMMF } from '@prisma/dmmf'

import { FETCHER_BOILERPLATE, generateModelClientClass, generateRootClientClass } from './crud-client-generator'
import { generateEnumType } from './enum-generator'
import {
  generateCreateInputType,
  generateModelInterface,
  generateOrderByInputType,
  generateUpdateInputType,
  generateWhereInputType,
  generateWhereUniqueInputType,
} from './model-types-generator'

const FILE_HEADER =
  '// This file was auto-generated by @prisma/rest-api-client-generator.\n' +
  '// Do not edit it manually.\n'

export type GenerateRestClientOptions = {
  dmmf: DMMF.Document
  outputDir: string
}

/**
 * Generates a typed REST API client for the given DMMF document and writes
 * three files into `outputDir`:
 *
 * - `types.ts`  — model interfaces and all CRUD argument types
 * - `client.ts` — `RestApiClient` class with per-model sub-clients
 * - `index.ts`  — re-exports from both files for a single import point
 */
export async function generateRestClient(options: GenerateRestClientOptions): Promise<void> {
  const { dmmf, outputDir } = options

  await fs.mkdir(outputDir, { recursive: true })

  await Promise.all([
    fs.writeFile(path.join(outputDir, 'types.ts'), FILE_HEADER + '\n' + buildTypesFile(dmmf), 'utf-8'),
    fs.writeFile(path.join(outputDir, 'client.ts'), FILE_HEADER + '\n' + buildClientFile(dmmf), 'utf-8'),
    fs.writeFile(path.join(outputDir, 'index.ts'), FILE_HEADER + '\n' + buildIndexFile(), 'utf-8'),
  ])
}

function buildTypesFile(dmmf: DMMF.Document): string {
  const sections: string[] = []

  for (const e of dmmf.datamodel.enums) {
    sections.push(generateEnumType(e))
  }

  for (const model of dmmf.datamodel.models) {
    sections.push(
      generateModelInterface(model),
      generateWhereInputType(model),
      generateWhereUniqueInputType(model),
      generateCreateInputType(model),
      generateUpdateInputType(model),
      generateOrderByInputType(model),
    )
  }

  return sections.join('\n\n') + '\n'
}

function buildClientFile(dmmf: DMMF.Document): string {
  const typeNames = dmmf.datamodel.models.flatMap((m) => [
    `  ${m.name},`,
    `  ${m.name}WhereInput,`,
    `  ${m.name}WhereUniqueInput,`,
    `  ${m.name}CreateInput,`,
    `  ${m.name}UpdateInput,`,
    `  ${m.name}OrderByInput,`,
  ])

  const sections: string[] = [
    `import type {\n${typeNames.join('\n')}\n} from './types'`,
    FETCHER_BOILERPLATE,
  ]

  for (const model of dmmf.datamodel.models) {
    sections.push(generateModelClientClass(model))
  }

  sections.push(generateRootClientClass(dmmf.datamodel.models))

  return sections.join('\n\n') + '\n'
}

function buildIndexFile(): string {
  return "export * from './types'\nexport * from './client'\n"
}

