import fs from 'node:fs/promises'
import os from 'node:os'
import path from 'node:path'

import type { DMMF } from '@prisma/dmmf'
import { afterEach, beforeEach, describe, expect, test } from 'vitest'

import { generateModelClientClass, generateRootClientClass } from '../crud-client-generator'
import { generateEnumType } from '../enum-generator'
import { fieldToTsType, scalarTypeToTs } from '../field-type-mapper'
import { generateRestClient } from '../generate-client'
import {
  generateCreateInputType,
  generateModelInterface,
  generateOrderByInputType,
  generateUpdateInputType,
  generateWhereInputType,
  generateWhereUniqueInputType,
} from '../model-types-generator'

// ──────────────────────────────────────────────────────────────────────────────
// Fixtures
// ──────────────────────────────────────────────────────────────────────────────

function makeField(overrides: Partial<DMMF.Field>): DMMF.Field {
  return {
    kind: 'scalar',
    name: 'id',
    isRequired: true,
    isList: false,
    isUnique: false,
    isId: true,
    isReadOnly: true,
    hasDefaultValue: true,
    type: 'Int',
    ...overrides,
  } as DMMF.Field
}

const userModel: DMMF.Model = {
  name: 'User',
  dbName: null,
  schema: null,
  fields: [
    makeField({ name: 'id', isId: true, isReadOnly: true, hasDefaultValue: true, type: 'Int' }),
    makeField({ name: 'email', isId: false, isReadOnly: false, isUnique: true, hasDefaultValue: false, type: 'String' }),
    makeField({ name: 'name', isId: false, isReadOnly: false, isRequired: false, hasDefaultValue: false, type: 'String' }),
    makeField({ name: 'role', isId: false, isReadOnly: false, hasDefaultValue: false, kind: 'enum', type: 'Role' }),
    makeField({
      name: 'posts',
      isId: false,
      isReadOnly: false,
      isRequired: true,
      isList: true,
      hasDefaultValue: false,
      kind: 'object',
      type: 'Post',
    }),
  ],
  uniqueFields: [],
  uniqueIndexes: [],
  primaryKey: null,
} as unknown as DMMF.Model

const roleEnum: DMMF.DatamodelEnum = {
  name: 'Role',
  values: [
    { name: 'ADMIN', dbName: null },
    { name: 'USER', dbName: null },
  ],
} as unknown as DMMF.DatamodelEnum

// ──────────────────────────────────────────────────────────────────────────────
// scalarTypeToTs
// ──────────────────────────────────────────────────────────────────────────────

describe('scalarTypeToTs', () => {
  test.each([
    ['String', 'string'],
    ['Boolean', 'boolean'],
    ['Int', 'number'],
    ['Float', 'number'],
    ['BigInt', 'bigint'],
    ['Decimal', 'string'],
    ['DateTime', 'string'],
    ['Json', 'unknown'],
    ['Bytes', 'string'],
    ['UnknownType', 'unknown'],
  ])('%s → %s', (prismaType, expected) => {
    expect(scalarTypeToTs(prismaType)).toBe(expected)
  })
})

// ──────────────────────────────────────────────────────────────────────────────
// fieldToTsType
// ──────────────────────────────────────────────────────────────────────────────

describe('fieldToTsType', () => {
  test('required scalar', () => {
    expect(fieldToTsType(makeField({ type: 'String', isRequired: true }))).toBe('string')
  })

  test('optional scalar becomes union with null', () => {
    expect(fieldToTsType(makeField({ type: 'String', isRequired: false }))).toBe('string | null')
  })

  test('list scalar', () => {
    expect(fieldToTsType(makeField({ type: 'Int', isList: true, isRequired: true }))).toBe('number[]')
  })

  test('enum field uses enum name', () => {
    expect(fieldToTsType(makeField({ kind: 'enum', type: 'Role', isRequired: true }))).toBe('Role')
  })

  test('relation field uses model name', () => {
    expect(fieldToTsType(makeField({ kind: 'object', type: 'Post', isRequired: true, isList: true }))).toBe('Post[]')
  })

  test('unsupported field maps to unknown', () => {
    expect(fieldToTsType(makeField({ kind: 'unsupported', type: 'geometry', isRequired: true }))).toBe('unknown')
  })
})

// ──────────────────────────────────────────────────────────────────────────────
// generateEnumType
// ──────────────────────────────────────────────────────────────────────────────

describe('generateEnumType', () => {
  test('produces a const enum with string values', () => {
    const result = generateEnumType(roleEnum)
    expect(result).toBe(
      "export const enum Role {\n  ADMIN = 'ADMIN',\n  USER = 'USER',\n}",
    )
  })
})

// ──────────────────────────────────────────────────────────────────────────────
// generateModelInterface
// ──────────────────────────────────────────────────────────────────────────────

describe('generateModelInterface', () => {
  test('includes all fields with correct types', () => {
    const result = generateModelInterface(userModel)
    expect(result).toContain('export interface User {')
    expect(result).toContain('id: number')
    expect(result).toContain('email: string')
    expect(result).toContain('name: string | null')
    expect(result).toContain('role: Role')
    expect(result).toContain('posts: Post[]')
  })
})

// ──────────────────────────────────────────────────────────────────────────────
// generateWhereInputType
// ──────────────────────────────────────────────────────────────────────────────

describe('generateWhereInputType', () => {
  test('all fields are optional and relation fields are excluded', () => {
    const result = generateWhereInputType(userModel)
    expect(result).toContain('export interface UserWhereInput {')
    expect(result).toContain('id?: number | null')
    expect(result).toContain('email?: string | null')
    expect(result).not.toContain('posts')
  })
})

// ──────────────────────────────────────────────────────────────────────────────
// generateWhereUniqueInputType
// ──────────────────────────────────────────────────────────────────────────────

describe('generateWhereUniqueInputType', () => {
  test('only id and unique fields are present', () => {
    const result = generateWhereUniqueInputType(userModel)
    expect(result).toContain('export interface UserWhereUniqueInput {')
    expect(result).toContain('id?: number')
    expect(result).toContain('email?: string')
    expect(result).not.toContain('name')
    expect(result).not.toContain('posts')
  })
})

// ──────────────────────────────────────────────────────────────────────────────
// generateCreateInputType
// ──────────────────────────────────────────────────────────────────────────────

describe('generateCreateInputType', () => {
  test('excludes id/readonly fields; required fields are non-optional', () => {
    const result = generateCreateInputType(userModel)
    expect(result).toContain('export interface UserCreateInput {')
    // email is required with no default → must be required
    expect(result).toContain('email: string')
    // name is optional (isRequired: false) → optional + nullable
    expect(result).toContain('name?: string | null')
    // id is isReadOnly + isId → excluded
    expect(result).not.toContain('id')
    // posts is a relation → excluded
    expect(result).not.toContain('posts')
  })
})

// ──────────────────────────────────────────────────────────────────────────────
// generateUpdateInputType
// ──────────────────────────────────────────────────────────────────────────────

describe('generateUpdateInputType', () => {
  test('all writable fields are optional', () => {
    const result = generateUpdateInputType(userModel)
    expect(result).toContain('export interface UserUpdateInput {')
    expect(result).toContain('email?: string')
    expect(result).toContain('name?: string | null')
    expect(result).not.toContain('id')
    expect(result).not.toContain('posts')
  })
})

// ──────────────────────────────────────────────────────────────────────────────
// generateOrderByInputType
// ──────────────────────────────────────────────────────────────────────────────

describe('generateOrderByInputType', () => {
  test('scalar and enum fields only, both directions allowed', () => {
    const result = generateOrderByInputType(userModel)
    expect(result).toContain("id?: 'asc' | 'desc'")
    expect(result).toContain("email?: 'asc' | 'desc'")
    expect(result).not.toContain('posts')
  })
})

// ──────────────────────────────────────────────────────────────────────────────
// generateModelClientClass
// ──────────────────────────────────────────────────────────────────────────────

describe('generateModelClientClass', () => {
  test('emits all five CRUD methods', () => {
    const result = generateModelClientClass(userModel)
    expect(result).toContain('export class UserClient {')
    expect(result).toContain('findMany(')
    expect(result).toContain('findUnique(')
    expect(result).toContain('create(')
    expect(result).toContain('update(')
    expect(result).toContain('delete(')
  })

  test('uses correct HTTP methods', () => {
    const result = generateModelClientClass(userModel)
    expect(result).toContain("method: 'GET'")
    expect(result).toContain("method: 'POST'")
    expect(result).toContain("method: 'PATCH'")
    expect(result).toContain("method: 'DELETE'")
  })

  test('route uses lower-cased model name', () => {
    const result = generateModelClientClass(userModel)
    expect(result).toContain('/user')
  })

  test('findMany uses correct arg types', () => {
    const result = generateModelClientClass(userModel)
    expect(result).toContain('where?: UserWhereInput')
    expect(result).toContain('orderBy?: UserOrderByInput')
    expect(result).toContain('Promise<User[]>')
  })

  test('findUnique accepts WhereUniqueInput and returns nullable', () => {
    const result = generateModelClientClass(userModel)
    expect(result).toContain('where: UserWhereUniqueInput')
    expect(result).toContain('Promise<User | null>')
  })
})

// ──────────────────────────────────────────────────────────────────────────────
// generateRootClientClass
// ──────────────────────────────────────────────────────────────────────────────

describe('generateRootClientClass', () => {
  test('declares a property for each model', () => {
    const result = generateRootClientClass([userModel])
    expect(result).toContain('export class RestApiClient {')
    expect(result).toContain('readonly user: UserClient')
    expect(result).toContain('new UserClient(baseUrl, fetcher)')
  })

  test('constructor defaults to defaultFetcher', () => {
    const result = generateRootClientClass([userModel])
    expect(result).toContain('fetcher: Fetcher = defaultFetcher')
  })
})

// ──────────────────────────────────────────────────────────────────────────────
// generateRestClient (integration)
// ──────────────────────────────────────────────────────────────────────────────

describe('generateRestClient', () => {
  let tmpDir: string

  beforeEach(async () => {
    tmpDir = await fs.mkdtemp(path.join(os.tmpdir(), 'rest-gen-test-'))
  })

  afterEach(async () => {
    await fs.rm(tmpDir, { recursive: true, force: true })
  })

  function makeDmmf(models: DMMF.Model[], enums: DMMF.DatamodelEnum[] = []): DMMF.Document {
