// This file was auto-generated by @prisma/rest-api-client-generator.
// Do not edit it manually.

import type {
  User,
  UserWhereInput,
  UserWhereUniqueInput,
  UserCreateInput,
  UserUpdateInput,
  UserOrderByInput,
} from './types'

export type Fetcher = (url: string, init?: RequestInit) => Promise<any>

async function defaultFetcher(url: string, init?: RequestInit): Promise<any> {
  const res = await fetch(url, init)
  if (!res.ok) {
    const body = await res.text().catch(() => '')
    throw new Error(`REST API error ${res.status}: ${body}`)
  }
  return res.json()
}

export class UserClient {
  constructor(private readonly baseUrl: string, private readonly fetcher: Fetcher) {}

  findMany(args?: {
    where?: UserWhereInput
    orderBy?: UserOrderByInput
    skip?: number
    take?: number
  }): Promise<User[]> {
    const params = new URLSearchParams()
    if (args?.where != null) params.set('where', JSON.stringify(args.where))
    if (args?.orderBy != null) params.set('orderBy', JSON.stringify(args.orderBy))
    if (args?.skip != null) params.set('skip', String(args.skip))
    if (args?.take != null) params.set('take', String(args.take))
    const qs = params.size > 0 ? `?${params}` : ''
    return this.fetcher(`${this.baseUrl}/user${qs}`, { method: 'GET' })
  }

  findUnique(args: { where: UserWhereUniqueInput }): Promise<User | null> {
    const params = new URLSearchParams({ where: JSON.stringify(args.where) })
    return this.fetcher(`${this.baseUrl}/user/unique?${params}`, { method: 'GET' })
  }

  create(args: { data: UserCreateInput }): Promise<User> {
    return this.fetcher(`${this.baseUrl}/user`, {
      method: 'POST',
      headers: { 'Content-Type': 'application/json' },
      body: JSON.stringify(args.data),
    })
  }

  update(args: { where: UserWhereUniqueInput; data: UserUpdateInput }): Promise<User> {
    const params = new URLSearchParams({ where: JSON.stringify(args.where) })
    return this.fetcher(`${this.baseUrl}/user?${params}`, {
      method: 'PATCH',
      headers: { 'Content-Type': 'application/json' },
      body: JSON.stringify(args.data),
    })
  }

  delete(args: { where: UserWhereUniqueInput }): Promise<User> {
    const params = new URLSearchParams({ where: JSON.stringify(args.where) })
    return this.fetcher(`${this.baseUrl}/user?${params}`, { method: 'DELETE' })
  }
}

export class RestApiClient {
  readonly user: UserClient

  constructor(baseUrl: string, fetcher: Fetcher = defaultFetcher) {
    this.user = new UserClient(baseUrl, fetcher)
  }
}

